        stmt.executeUpdate();
        stmt.close();
        stmt = getStatement(conn, "delete from accountprofileejb");
        stmt.executeUpdate();
        stmt.close();
        stmt = getStatement(conn, "delete from holdingejb");
        stmt.executeUpdate();
        stmt.close();
